import React, { useState, useEffect, useRef } from "react";
import {
  UserPlus, Search, Trash2, RefreshCw, X, CheckCircle,
  AlertCircle, Shield, ChevronDown, Eye, EyeOff, UserMinus,
  Users, Filter,
} from "lucide-react";
import api from "../../api.js";
import "../dashboard/Dashboard.css";
import "../../components/Components.css";

const ROLE_OPTIONS = [
  "Lead_Investigator",
  "Forensic_Officer",
  "Police_Officer",
  "Supervising_Officer",
];

const ROLE_STYLE = {
  Lead_Investigator:    { color: "#34d399", bg: "rgba(52,211,153,0.1)",   label: "Lead Investigator"    },
  Forensic_Officer:     { color: "#fbbf24", bg: "rgba(251,191,36,0.1)",   label: "Forensic Officer"     },
  Police_Officer:       { color: "#60a5fa", bg: "rgba(96,165,250,0.1)",   label: "Police Officer"       },
  Supervising_Officer:  { color: "#818cf8", bg: "rgba(129,140,248,0.1)",  label: "Supervising Officer"  },
};

// ── sub-components ────────────────────────────────────────────────────────────
function RoleBadge({ role }) {
  const s = ROLE_STYLE[role] || { color: "#94a3b8", bg: "rgba(148,163,184,0.1)", label: role?.replace(/_/g, " ") || "—" };
  return (
    <span style={{ background: s.bg, color: s.color, padding: "3px 10px", borderRadius: 6, fontSize: "11px", fontWeight: 700, whiteSpace: "nowrap" }}>
      {s.label}
    </span>
  );
}

function Flash({ msg }) {
  if (!msg.text) return null;
  return (
    <div className={`alertBanner ${msg.type === "success" ? "alertSuccess" : "alertError"}`}
      style={{ display: "flex", alignItems: "center", gap: "0.5rem", marginBottom: "1rem" }}>
      {msg.type === "success" ? <CheckCircle size={15} /> : <AlertCircle size={15} />}
      {msg.text}
    </div>
  );
}

// ── Add Member Modal ───────────────────────────────────────────────────────────
function AddMemberModal({ onClose, onSuccess, flash }) {
  const [form, setForm] = useState({ name: "", email: "", role_name: "", password: "", Region: "" });
  const [showPass, setShowPass] = useState(false);
  const [saving, setSaving] = useState(false);
  const [err, setErr] = useState("");

  const set = (k, v) => setForm((p) => ({ ...p, [k]: v }));

  const handleSubmit = async () => {
    setErr("");
    if (!form.name.trim() || !form.email.trim() || !form.role_name)
      return setErr("Name, email, and role are required.");

    setSaving(true);
    try {
      const payload = { ...form, password: form.password || "LegalLens@123" };
      const res = await api.post("/users/create", payload);
      flash("success", res.data?.message || `${form.name} added to system`);
      onSuccess();
      onClose();
    } catch (e) {
      setErr(e.response?.data?.message || "Failed to create member");
    } finally {
      setSaving(false);
    }
  };

  return (
    <div className="modalOverlay" onClick={(e) => e.target === e.currentTarget && onClose()}>
      <div className="modalBox" style={{ maxWidth: 520 }}>
        <div className="modalHeader">
          <div>
            <p className="modalTitle">Add New Team Member</p>
            <p className="modalSubtitle">Create a new system account and assign a role</p>
          </div>
          <button className="modalCloseBtn" onClick={onClose}><X size={16} /></button>
        </div>

        <div className="modalBody">
          {err && (
            <div className="alertBanner alertError" style={{ display: "flex", alignItems: "center", gap: "0.5rem" }}>
              <AlertCircle size={14} /> {err}
            </div>
          )}

          <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: "1rem" }}>
            <div className="modalField">
              <label>Full Name *</label>
              <input className="modalInput" placeholder="e.g. Arjun Sharma"
                value={form.name} onChange={(e) => set("name", e.target.value)} />
            </div>
            <div className="modalField">
              <label>Email Address *</label>
              <input className="modalInput" type="email" placeholder="officer@agency.gov"
                value={form.email} onChange={(e) => set("email", e.target.value)} />
            </div>

            <div className="modalField">
              <label>Role *</label>
              <div style={{ position: "relative" }}>
                <select className="modalInput" style={{ paddingRight: "2.5rem", cursor: "pointer" }}
                  value={form.role_name} onChange={(e) => set("role_name", e.target.value)}>
                  <option value="">Select role…</option>
                  {ROLE_OPTIONS.map((r) => (
                    <option key={r} value={r}>{r.replace(/_/g, " ")}</option>
                  ))}
                </select>
                <ChevronDown size={14} style={{ position: "absolute", right: "0.75rem", top: "50%", transform: "translateY(-50%)", color: "#64748b", pointerEvents: "none" }} />
              </div>
            </div>

            <div className="modalField">
              <label>Region / Station</label>
              <input className="modalInput" placeholder="e.g. Pune East"
                value={form.Region} onChange={(e) => set("Region", e.target.value)} />
            </div>

            <div className="modalField" style={{ gridColumn: "span 2" }}>
              <label>Temporary Password <span style={{ color: "#475569", fontSize: "0.7rem", fontWeight: 400 }}>(default: LegalLens@123)</span></label>
              <div style={{ position: "relative" }}>
                <input className="modalInput" type={showPass ? "text" : "password"}
                  placeholder="Leave blank to use default"
                  value={form.password} onChange={(e) => set("password", e.target.value)}
                  style={{ paddingRight: "2.75rem" }} />
                <button onClick={() => setShowPass((v) => !v)}
                  style={{ position: "absolute", right: "0.75rem", top: "50%", transform: "translateY(-50%)", background: "none", border: "none", color: "#64748b", cursor: "pointer", display: "flex" }}>
                  {showPass ? <EyeOff size={16} /> : <Eye size={16} />}
                </button>
              </div>
            </div>
          </div>
        </div>

        <div className="modalFooter">
          <button className="btnCancel" onClick={onClose} disabled={saving}>Cancel</button>
          <button className="btnCreate" onClick={handleSubmit} disabled={saving}>
            {saving ? <><div className="miniSpinner" style={{ width: 14, height: 14, marginRight: 6 }} />Creating…</> : <><UserPlus size={15} /> Add Member</>}
          </button>
        </div>
      </div>
    </div>
  );
}

// ── Reset Password Modal ───────────────────────────────────────────────────────
function ResetPasswordModal({ member, onClose, flash }) {
  const [newPass, setNewPass] = useState("");
  const [showPass, setShowPass] = useState(false);
  const [saving, setSaving] = useState(false);
  const [err, setErr] = useState("");

  const handleReset = async () => {
    setErr("");
    if (!newPass || newPass.length < 6) return setErr("Password must be at least 6 characters");
    setSaving(true);
    try {
      const res = await api.post(`/users/${member._id}/reset-password`, { newPassword: newPass });
      flash("success", res.data?.message || `Password reset for ${member.name}`);
      onClose();
    } catch (e) {
      setErr(e.response?.data?.message || "Failed to reset password");
    } finally {
      setSaving(false);
    }
  };

  return (
    <div className="modalOverlay" onClick={(e) => e.target === e.currentTarget && onClose()}>
      <div className="modalBox" style={{ maxWidth: 420 }}>
        <div className="modalHeader">
          <div>
            <p className="modalTitle">Reset Password</p>
            <p className="modalSubtitle">Set a new password for <strong style={{ color: "#818cf8" }}>{member.name}</strong></p>
          </div>
          <button className="modalCloseBtn" onClick={onClose}><X size={16} /></button>
        </div>

        <div className="modalBody">
          {err && <div className="alertBanner alertError" style={{ display: "flex", alignItems: "center", gap: "0.5rem" }}><AlertCircle size={14} /> {err}</div>}

          <div className="modalField">
            <label>New Password *</label>
            <div style={{ position: "relative" }}>
              <input className="modalInput" type={showPass ? "text" : "password"}
                placeholder="Min. 6 characters" value={newPass}
                onChange={(e) => setNewPass(e.target.value)}
                style={{ paddingRight: "2.75rem" }}
                onKeyDown={(e) => e.key === "Enter" && handleReset()} />
              <button onClick={() => setShowPass((v) => !v)}
                style={{ position: "absolute", right: "0.75rem", top: "50%", transform: "translateY(-50%)", background: "none", border: "none", color: "#64748b", cursor: "pointer", display: "flex" }}>
                {showPass ? <EyeOff size={16} /> : <Eye size={16} />}
              </button>
            </div>
            <p style={{ color: "#475569", fontSize: "0.75rem", margin: 0 }}>
              The member will be notified via a system notification.
            </p>
          </div>
        </div>

        <div className="modalFooter">
          <button className="btnCancel" onClick={onClose} disabled={saving}>Cancel</button>
          <button className="btnCreate" onClick={handleReset} disabled={saving}>
            {saving ? <><div className="miniSpinner" style={{ width: 14, height: 14, marginRight: 6 }} />Resetting…</> : <><RefreshCw size={15} /> Reset Password</>}
          </button>
        </div>
      </div>
    </div>
  );
}

// ── Confirm Delete Modal ───────────────────────────────────────────────────────
function ConfirmModal({ title, message, confirmLabel, confirmColor, onConfirm, onClose, loading }) {
  return (
    <div className="modalOverlay" onClick={(e) => e.target === e.currentTarget && onClose()}>
      <div className="modalBox" style={{ maxWidth: 420 }}>
        <div className="modalHeader">
          <div>
            <p className="modalTitle">{title}</p>
            <p className="modalSubtitle">{message}</p>
          </div>
          <button className="modalCloseBtn" onClick={onClose}><X size={16} /></button>
        </div>
        <div className="modalFooter" style={{ paddingTop: "1rem" }}>
          <button className="btnCancel" onClick={onClose} disabled={loading}>Cancel</button>
          <button
            onClick={onConfirm}
            disabled={loading}
            style={{
              display: "flex", alignItems: "center", gap: "0.5rem",
              background: confirmColor || "#ef4444", border: "none",
              color: "#fff", padding: "0.75rem 1.5rem", borderRadius: 8,
              fontSize: "0.875rem", fontWeight: 700, cursor: loading ? "not-allowed" : "pointer",
              opacity: loading ? 0.7 : 1,
            }}>
            {loading ? <div className="miniSpinner" style={{ width: 14, height: 14 }} /> : confirmLabel}
          </button>
        </div>
      </div>
    </div>
  );
}

// ── Main Page ─────────────────────────────────────────────────────────────────
export default function MembersPage() {
  const [members, setMembers]             = useState([]);
  const [filtered, setFiltered]           = useState([]);
  const [loading, setLoading]             = useState(true);
  const [search, setSearch]               = useState("");
  const [roleFilter, setRoleFilter]       = useState("All");
  const [showAddModal, setShowAddModal]   = useState(false);
  const [resetTarget, setResetTarget]     = useState(null);
  const [deleteTarget, setDeleteTarget]   = useState(null);
  const [removeCasesTarget, setRemoveCasesTarget] = useState(null);
  const [actionLoading, setActionLoading] = useState(false);
  const [msg, setMsg]                     = useState({ type: "", text: "" });
  const [showFilter, setShowFilter]       = useState(false);
  const filterRef                         = useRef(null);

  const flash = (type, text) => {
    setMsg({ type, text });
    setTimeout(() => setMsg({ type: "", text: "" }), 4000);
  };

  const fetchMembers = async () => {
    setLoading(true);
    try {
      const res = await api.get("/users");
      setMembers(Array.isArray(res.data) ? res.data : []);
    } catch {
      flash("error", "Failed to load members");
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => { fetchMembers(); }, []);

  useEffect(() => {
    let list = members;
    if (search) {
      const q = search.toLowerCase();
      list = list.filter(
        (m) =>
          m.name?.toLowerCase().includes(q) ||
          m.email?.toLowerCase().includes(q) ||
          m.Region?.toLowerCase().includes(q)
      );
    }
    if (roleFilter !== "All") {
      list = list.filter((m) => m.role_id?.role_name === roleFilter);
    }
    setFiltered(list);
  }, [search, roleFilter, members]);

  // Close filter dropdown on outside click
  useEffect(() => {
    const handler = (e) => {
      if (filterRef.current && !filterRef.current.contains(e.target)) setShowFilter(false);
    };
    document.addEventListener("mousedown", handler);
    return () => document.removeEventListener("mousedown", handler);
  }, []);

  const handleDelete = async () => {
    setActionLoading(true);
    try {
      await api.delete(`/users/${deleteTarget._id}`);
      flash("success", `${deleteTarget.name} permanently deleted`);
      setDeleteTarget(null);
      fetchMembers();
    } catch (e) {
      flash("error", e.response?.data?.message || "Failed to delete member");
      setDeleteTarget(null);
    } finally {
      setActionLoading(false);
    }
  };

  const handleRemoveFromCases = async () => {
    setActionLoading(true);
    try {
      await api.delete(`/users/${removeCasesTarget._id}/cases`);
      flash("success", `${removeCasesTarget.name} removed from all cases`);
      setRemoveCasesTarget(null);
    } catch (e) {
      flash("error", e.response?.data?.message || "Failed to remove from cases");
      setRemoveCasesTarget(null);
    } finally {
      setActionLoading(false);
    }
  };

  // Role count stats
  const roleCounts = ROLE_OPTIONS.reduce((acc, r) => {
    acc[r] = members.filter((m) => m.role_id?.role_name === r).length;
    return acc;
  }, {});

  return (
    <div className="dashboardMain">
      {/* Header */}
      <header className="dashboardHeader">
        <div className="headerBranding">
          <h1 className="logoText"><span>LEGALLENS</span> Team Members</h1>
          <p className="systemStatus">
            Manage system accounts and role assignments •{" "}
            <span className="highlightText">{members.length} total member{members.length !== 1 ? "s" : ""}</span>
          </p>
        </div>
        <button
          className="primaryActionBtn"
          style={{ width: "auto", padding: "0.75rem 1.5rem" }}
          onClick={() => setShowAddModal(true)}
        >
          <UserPlus size={16} /> Add Member
        </button>
      </header>

      {/* Flash message */}
      <Flash msg={msg} />

      {/* Role stat chips */}
      <div style={{ display: "flex", gap: "0.75rem", flexWrap: "wrap", marginBottom: "1.5rem" }}>
        <button
          onClick={() => setRoleFilter("All")}
          style={{
            display: "flex", alignItems: "center", gap: "0.5rem",
            padding: "6px 14px", borderRadius: 20, fontSize: "0.78rem", fontWeight: 700,
            cursor: "pointer", border: "1px solid",
            background: roleFilter === "All" ? "rgba(99,102,241,0.15)" : "transparent",
            color: roleFilter === "All" ? "#818cf8" : "#64748b",
            borderColor: roleFilter === "All" ? "rgba(99,102,241,0.35)" : "rgba(255,255,255,0.06)",
          }}>
          <Users size={12} /> All <span style={{ background: "rgba(255,255,255,0.06)", borderRadius: 10, padding: "1px 7px" }}>{members.length}</span>
        </button>
        {ROLE_OPTIONS.map((r) => {
          const s = ROLE_STYLE[r];
          const active = roleFilter === r;
          return (
            <button key={r} onClick={() => setRoleFilter(r)}
              style={{
                display: "flex", alignItems: "center", gap: "0.5rem",
                padding: "6px 14px", borderRadius: 20, fontSize: "0.78rem", fontWeight: 700,
                cursor: "pointer", border: "1px solid",
                background: active ? s.bg : "transparent",
                color: active ? s.color : "#64748b",
                borderColor: active ? s.color.replace(")", ", 0.4)").replace("rgb", "rgba") : "rgba(255,255,255,0.06)",
                transition: "all 0.2s",
              }}>
              {s.label.split(" ")[0]} <span style={{ background: "rgba(255,255,255,0.06)", borderRadius: 10, padding: "1px 7px" }}>{roleCounts[r] || 0}</span>
            </button>
          );
        })}
      </div>

      {/* Search bar */}
      <div style={{ display: "flex", gap: "1rem", marginBottom: "1.5rem", alignItems: "center" }}>
        <div className="membersSearch" style={{ flex: 1, maxWidth: 420 }}>
          <Search size={16} color="#475569" />
          <input
            type="text"
            placeholder="Search by name, email, or region…"
            value={search}
            onChange={(e) => setSearch(e.target.value)}
            style={{ background: "transparent", border: "none", outline: "none", color: "#fff", fontSize: "0.875rem", flex: 1 }}
          />
          {search && (
            <button onClick={() => setSearch("")}
              style={{ background: "none", border: "none", color: "#64748b", cursor: "pointer", display: "flex" }}>
              <X size={14} />
            </button>
          )}
        </div>
        <span style={{ color: "#64748b", fontSize: "0.8rem" }}>
          {filtered.length} result{filtered.length !== 1 ? "s" : ""}
        </span>
      </div>

      {/* Members Table */}
      <div className="formSectionCard">
        <div className="sectionHeader" style={{ padding: "1.25rem 1.5rem", marginBottom: 0, borderBottom: "1px solid rgba(255,255,255,0.05)" }}>
          <div className="indicatorDot" />
          <h2 style={{ margin: 0, fontSize: "0.75rem", textTransform: "uppercase", letterSpacing: "0.15em", color: "#94a3b8", fontWeight: 800 }}>
            MEMBER RECORDS
          </h2>
        </div>

        {loading ? (
          <div style={{ textAlign: "center", padding: "3rem", color: "#475569" }}>
            <div className="miniSpinner" style={{ margin: "0 auto 0.75rem" }} />
            <p style={{ margin: 0 }}>Loading members…</p>
          </div>
        ) : filtered.length === 0 ? (
          <div style={{ textAlign: "center", padding: "3rem", color: "#475569" }}>
            <Users size={40} style={{ marginBottom: "0.75rem", opacity: 0.3 }} />
            <p style={{ margin: 0 }}>{search ? `No members matching "${search}"` : "No members found"}</p>
            <button className="primaryActionBtn" style={{ width: "auto", marginTop: "1.25rem", padding: "0.6rem 1.5rem" }} onClick={() => setShowAddModal(true)}>
              <UserPlus size={15} /> Add First Member
            </button>
          </div>
        ) : (
          <table className="legalTable">
            <thead>
              <tr>
                <th>#</th>
                <th>Member</th>
                <th>Role</th>
                <th>Region / Station</th>
                <th style={{ textAlign: "right" }}>Actions</th>
              </tr>
            </thead>
            <tbody>
              {filtered.map((m, i) => (
                <MemberRow
                  key={m._id}
                  member={m}
                  index={i + 1}
                  onReset={() => setResetTarget(m)}
                  onDelete={() => setDeleteTarget(m)}
                  onRemoveCases={() => setRemoveCasesTarget(m)}
                />
              ))}
            </tbody>
          </table>
        )}
      </div>

      {/* Modals */}
      {showAddModal && (
        <AddMemberModal
          onClose={() => setShowAddModal(false)}
          onSuccess={fetchMembers}
          flash={flash}
        />
      )}
      {resetTarget && (
        <ResetPasswordModal
          member={resetTarget}
          onClose={() => setResetTarget(null)}
          flash={flash}
        />
      )}
      {deleteTarget && (
        <ConfirmModal
          title="Delete Member"
          message={`Permanently delete "${deleteTarget.name}"? This will remove them from all cases and cannot be undone.`}
          confirmLabel="Delete Permanently"
          confirmColor="#ef4444"
          onConfirm={handleDelete}
          onClose={() => setDeleteTarget(null)}
          loading={actionLoading}
        />
      )}
      {removeCasesTarget && (
        <ConfirmModal
          title="Remove from All Cases"
          message={`Remove "${removeCasesTarget.name}" from all assigned cases? Their system account will remain active.`}
          confirmLabel="Remove from Cases"
          confirmColor="#f59e0b"
          onConfirm={handleRemoveFromCases}
          onClose={() => setRemoveCasesTarget(null)}
          loading={actionLoading}
        />
      )}
    </div>
  );
}

// ── Member Row ────────────────────────────────────────────────────────────────
function MemberRow({ member, index, onReset, onDelete, onRemoveCases }) {
  const [showMenu, setShowMenu] = useState(false);
  const menuRef = useRef(null);

  useEffect(() => {
    const handler = (e) => {
      if (menuRef.current && !menuRef.current.contains(e.target)) setShowMenu(false);
    };
    document.addEventListener("mousedown", handler);
    return () => document.removeEventListener("mousedown", handler);
  }, []);

  const roleName = member.role_id?.role_name;

  return (
    <tr style={{ transition: "background 0.15s" }}>
      <td className="mutedText" style={{ fontFamily: "monospace", fontSize: "0.75rem" }}>
        {String(index).padStart(3, "0")}
      </td>
      <td>
        <div className="nameCell">
          <div className="avatarCircle">
            {member.name?.charAt(0)?.toUpperCase() || "?"}
          </div>
          <div>
            <p className="boldText" style={{ margin: 0, fontSize: "0.875rem" }}>{member.name}</p>
            <p className="mutedText" style={{ margin: 0, fontSize: "0.75rem" }}>{member.email}</p>
          </div>
        </div>
      </td>
      <td>
        {roleName ? <RoleBadge role={roleName} /> : <span className="mutedText">—</span>}
      </td>
      <td className="mutedText" style={{ fontSize: "0.8rem" }}>
        {member.Region || <span style={{ color: "#334155" }}>—</span>}
      </td>
      <td>
        <div style={{ display: "flex", justifyContent: "flex-end" }} ref={menuRef}>
          <div style={{ position: "relative" }}>
            <button
              className="actionCircle"
              onClick={() => setShowMenu((v) => !v)}
              title="Member actions"
              style={{ gap: "4px", padding: "8px 10px", fontSize: "0.8rem" }}
            >
              ···
            </button>
            {showMenu && (
              <div className="actionDropdown" style={{ right: 0 }}>
                <button className="actionDropItem" onClick={() => { onReset(); setShowMenu(false); }}>
                  <RefreshCw size={14} color="#818cf8" /> Reset Password
                </button>
                <button className="actionDropItem" onClick={() => { onRemoveCases(); setShowMenu(false); }}>
                  <UserMinus size={14} color="#fbbf24" /> Remove from Cases
                </button>
                <button className="actionDropItem" onClick={() => { onDelete(); setShowMenu(false); }}
                  style={{ color: "#f87171" }}>
                  <Trash2 size={14} color="#f87171" /> Delete Member
                </button>
              </div>
            )}
          </div>
        </div>
      </td>
    </tr>
  );
}
